import { Button } from "@/components/ui/button";
import { Parameter, ParameterValue, Tool, Command } from "@/registry/commandly/lib/types/commandly";
import { getCommandPath } from "@/registry/commandly/lib/utils/commandly";
import { TerminalIcon, CopyIcon, SaveIcon } from "lucide-react";
import { useCallback, useEffect, useState, useMemo } from "react";
import { toast } from "sonner";

interface GeneratedCommandProps {
  tool: Tool;
  selectedCommand?: Command;
  parameterValues: Record<string, ParameterValue>;
  onSaveCommand?: (command: string) => void;
}

export function GeneratedCommand({
  tool,
  selectedCommand,
  parameterValues,
  onSaveCommand,
}: GeneratedCommandProps) {
  selectedCommand = selectedCommand || tool.commands[0];
  const [generatedCommand, setGeneratedCommand] = useState("");

  const globalParameters = useMemo(() => {
    return tool.parameters?.filter((p) => p.isGlobal) || [];
  }, [tool]);

  const currentParameters = useMemo(() => {
    return tool?.parameters?.filter((p) => p.commandKey === selectedCommand.key) || [];
  }, [tool, selectedCommand]);

  const generateCommand = useCallback(() => {
    const commandPath = getCommandPath(selectedCommand, tool);
    let command = tool.name == commandPath ? tool.name : `${tool.name} ${commandPath}`;

    const parametersWithValues: Array<{
      param: Parameter;
      value: ParameterValue;
    }> = [];

    globalParameters.forEach((param) => {
      const value = parameterValues[param.key];
      if (value !== undefined && value !== "" && value !== false) {
        parametersWithValues.push({ param, value });
      }
    });

    currentParameters.forEach((param) => {
      const value = parameterValues[param.key];
      if (value !== undefined && value !== "" && value !== false && !param.isGlobal) {
        parametersWithValues.push({ param, value });
      }
    });

    const positionalParams = parametersWithValues
      .filter(({ param }) => param.parameterType === "Argument")
      .sort((a, b) => (a.param.position || 0) - (b.param.position || 0));

    parametersWithValues.forEach(({ param, value }) => {
      if (param.parameterType === "Flag") {
        if (value === true) {
          const flag = param.shortFlag || param.longFlag;
          if (flag) command += ` ${flag}`;
        }
      } else if (param.parameterType === "Option") {
        const flag = param.shortFlag || param.longFlag;
        if (flag) {
          const separator = param.keyValueSeparator ?? " ";
          command += ` ${flag}${separator}${value}`;
        }
      } else if (param.parameterType === "Argument") {
        command += ` ${value}`;
      }
    });

    positionalParams.forEach(({ value }) => {
      command += ` ${value}`;
    });

    setGeneratedCommand(command);
  }, [tool, parameterValues, selectedCommand, globalParameters, currentParameters]);

  useEffect(() => {
    generateCommand();
  }, [generateCommand]);

  const copyCommand = () => {
    navigator.clipboard.writeText(generatedCommand);
    toast("Command copied!");
  };

  return (
    <div>
      {tool.commands.length === 0 ? (
        <div className="py-8 text-center">
          <TerminalIcon className="mx-auto mb-4 h-12 w-12 text-muted-foreground" />
          <p className="text-muted-foreground">No commands available for this tool.</p>
        </div>
      ) : generatedCommand ? (
        <div className="space-y-4">
          <div className="rounded bg-muted p-4 font-mono text-sm">{generatedCommand}</div>
          <div className="flex gap-2">
            <Button
              onClick={copyCommand}
              variant="outline"
              className="flex-1"
            >
              <CopyIcon className="mr-2 h-4 w-4" />
              Copy Command
            </Button>
            {onSaveCommand && (
              <Button
                onClick={() => onSaveCommand(generatedCommand)}
                variant="outline"
                className="flex-1"
              >
                <SaveIcon className="mr-2 h-4 w-4" />
                Save Command
              </Button>
            )}
          </div>
        </div>
      ) : (
        <div className="py-8 text-center">
          <TerminalIcon className="mx-auto mb-4 h-12 w-12 text-muted-foreground" />
          <p className="text-muted-foreground">Configure parameters to generate the command.</p>
        </div>
      )}
    </div>
  );
}

import { Button } from "@/components/ui/button";
import { Card, CardAction, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Command as UICommand,
  CommandGroup,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { ScrollArea, ScrollBar } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";
import { Tool } from "@/registry/commandly/lib/types/commandly";
import { exportToStructuredJSON } from "@/registry/commandly/lib/utils/commandly";
import { convertToNestedStructure } from "@/registry/commandly/lib/utils/commandly-nested";
import { CheckIcon, ChevronsUpDownIcon, CopyIcon } from "lucide-react";
import { useQueryState } from "nuqs";
import { useEffect, useState } from "react";
import { toast } from "sonner";

const jsonOptions = [
  { value: "nested", label: "Nested" },
  { value: "flat", label: "Flat" },
];

interface JsonTypeComponentProps {
  tool: Tool;
}

export function JsonOutput({ tool }: JsonTypeComponentProps) {
  const [open, setOpen] = useState(false);
  const [jsonString, setJsonString] = useState<string>();
  const [jsonType, setJsonType] = useQueryState("output", {
    defaultValue: "flat",
  });
  useEffect(() => {
    const config =
      jsonType === "flat" ? exportToStructuredJSON(tool) : convertToNestedStructure(tool);
    setJsonString(JSON.stringify(config, null, 2));
  }, [jsonType, tool]);

  return (
    <Card>
      <CardHeader>
        <CardTitle>
          <span className="text-sm">Output type: </span>
          <Popover
            open={open}
            onOpenChange={setOpen}
          >
            <PopoverTrigger asChild>
              <Button
                variant="outline"
                role="combobox"
                aria-expanded={open}
                className="w-48 justify-between"
              >
                {jsonOptions.find((option) => option.value === jsonType)?.label}
                <ChevronsUpDownIcon className="opacity-50" />
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-48 p-0">
              <UICommand>
                <CommandList>
                  <CommandGroup>
                    {jsonOptions.map((option) => (
                      <CommandItem
                        key={option.value}
                        value={option.value}
                        onSelect={(currentValue) => {
                          setJsonType(currentValue);
                          setOpen(false);
                        }}
                      >
                        {option.label}
                        <CheckIcon
                          className={cn(
                            "ml-auto h-4 w-4",
                            jsonType === option.value ? "opacity-100" : "opacity-0",
                          )}
                        />
                      </CommandItem>
                    ))}
                  </CommandGroup>
                </CommandList>
              </UICommand>
            </PopoverContent>
          </Popover>
        </CardTitle>
        <CardAction
          className="rounded-md"
          onClick={() => {
            navigator.clipboard.writeText(jsonString!);
            toast("Copied!");
          }}
        >
          <CopyIcon className="h-4 w-4 dark:stroke-primary" />
        </CardAction>
      </CardHeader>
      <CardContent>
        <ScrollArea
          className="max-w-full *:data-radix-scroll-area-viewport:max-h-[calc(100vh-320px)]"
          type="hover"
        >
          <pre className="max-h max-w-full rounded-md bg-card font-mono text-sm dark:text-gray-200">
            {jsonString}
          </pre>
          <ScrollBar orientation="vertical" />
          <ScrollBar orientation="horizontal" />
        </ScrollArea>
      </CardContent>
    </Card>
  );
}

import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { Parameter, ParameterValue } from "@/registry/commandly/lib/types/commandly";
import { Command, Tool } from "@/registry/commandly/lib/types/commandly";
import { InfoIcon } from "lucide-react";
import React from "react";

const findDefaultCommand = (tool: Tool): Command | null => {
  const defaultCommand = tool.commands.find((command) => command.isDefault);
  if (defaultCommand) return defaultCommand;

  const nameMatchCommand = tool.commands.find(
    (command) => command.name.toLowerCase() === tool.name.toLowerCase(),
  );
  if (nameMatchCommand) return nameMatchCommand;

  return tool.commands.length > 0 ? tool.commands[0] : null;
};

interface ParameterLabelProps {
  name: string;
  longFlag?: string;
  shortFlag?: string;
  isRequired?: boolean;
  isGlobal?: boolean;
  description?: string;
  className?: string;
  children?: React.ReactNode;
}

function ParameterLabel({
  name,
  longFlag,
  shortFlag,
  isRequired,
  isGlobal,
  description,
  className,
  children,
}: ParameterLabelProps) {
  return (
    <Label className={className}>
      {name}
      {(longFlag || shortFlag) && (
        <span className="ml-1 text-muted-foreground">
          ({[longFlag, shortFlag].filter(Boolean).join(", ")})
        </span>
      )}
      {isRequired && <span className="ml-1 text-destructive">*</span>}
      <Tooltip>
        <TooltipTrigger>
          <InfoIcon className="h-3.5 w-3.5" />
        </TooltipTrigger>
        <TooltipContent>
          <span>{description}</span>
        </TooltipContent>
      </Tooltip>
      {children}
      {isGlobal && (
        <Badge
          variant="outline"
          className="ml-2 text-xs"
        >
          global
        </Badge>
      )}
    </Label>
  );
}

type ParameterInputProps = {
  parameter: Parameter;
  value: ParameterValue;
  onUpdate: (value: ParameterValue) => void;
};

function FlagInput({ parameter, value, onUpdate }: ParameterInputProps) {
  return (
    <div className="flex items-center space-x-2">
      <Switch
        checked={value === "true" || value === true}
        onCheckedChange={onUpdate}
      />
      <ParameterLabel
        className="flex-1 select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
    </div>
  );
}

function OptionEnumInput({ parameter, value, onUpdate }: ParameterInputProps) {
  return (
    <div className="space-y-2">
      <ParameterLabel
        className="select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
      <Select
        value={value as string}
        onValueChange={onUpdate}
      >
        <SelectTrigger>
          <SelectValue placeholder="Select an option" />
        </SelectTrigger>
        <SelectContent>
          {parameter.enumValues?.map((enumValue) => (
            <SelectItem
              key={enumValue.key}
              value={enumValue.value}
            >
              {enumValue.displayName || enumValue.value}
            </SelectItem>
          ))}
        </SelectContent>
      </Select>
    </div>
  );
}

function OptionBooleanInput({ parameter, value, onUpdate }: ParameterInputProps) {
  return (
    <div className="flex items-center space-x-2">
      <Switch
        checked={value === "true" || value === true}
        onCheckedChange={(checked) => onUpdate(checked.toString())}
      />
      <ParameterLabel
        className="flex-1 select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
    </div>
  );
}

function OptionTextInput({ parameter, value, onUpdate }: ParameterInputProps) {
  return (
    <div className="space-y-2">
      <ParameterLabel
        className="flex-1 select-auto"
        name={parameter.name}
        longFlag={parameter.longFlag}
        shortFlag={parameter.shortFlag}
        isRequired={parameter.isRequired}
        isGlobal={parameter.isGlobal}
        description={parameter.description}
      />
      <Input
        type={parameter.dataType === "Number" ? "number" : "text"}
        value={parameter.dataType === "Number" ? (value as number) : (value as string)}
        onChange={(e) => onUpdate(e.target.value)}
        placeholder="Enter value"
      />
    </div>
  );
}

function ArgumentInput({ parameter, value, onUpdate }: ParameterInputProps) {
  return (
    <div className="space-y-2">
      <ParameterLabel
        name={parameter.name}
        isRequired={parameter.isRequired}
        description={parameter.description}
      >
        <Badge
          variant="secondary"
          className="ml-2 text-xs"
        >
          {parameter.parameterType}
          {parameter.position !== undefined && ` (${parameter.position})`}
        </Badge>
      </ParameterLabel>
      <Input
        type={parameter.dataType === "Number" ? "number" : "text"}
        value={parameter.dataType === "Number" ? (value as number) : (value as string)}
        onChange={(e) => onUpdate(e.target.value)}
        placeholder="Enter value"
      />
    </div>
  );
}

interface RuntimePreviewProps {
  selectedCommand?: Command | null;
  tool: Tool;
  parameterValues: Record<string, ParameterValue>;
  updateParameterValue: (parameterKey: string, value: ParameterValue) => void;
}

export function RuntimePreview({
  selectedCommand: providedCommand,
  tool,
  parameterValues,
  updateParameterValue,
}: RuntimePreviewProps) {
  const selectedCommand = providedCommand ?? findDefaultCommand(tool);

  return (
    <React.Fragment>
      {selectedCommand && tool.commands.length === 0 ? (
        <p className="text-sm text-muted-foreground">No commands available for this tool.</p>
      ) : (
        <div className="space-y-4">
          {tool.parameters.length > 0 ? (
            tool.parameters
              .filter((param) => param.commandKey === selectedCommand?.key || param.isGlobal)
              .map((parameter) => {
                const value = parameterValues[parameter.key] || parameter.defaultValue || "";
                const onUpdate = (val: ParameterValue) => updateParameterValue(parameter.key, val);

                if (parameter.parameterType === "Flag") {
                  return (
                    <FlagInput
                      key={parameter.key}
                      parameter={parameter}
                      value={value}
                      onUpdate={onUpdate}
                    />
                  );
                }
                if (parameter.parameterType === "Argument") {
                  return (
                    <ArgumentInput
                      key={parameter.key}
                      parameter={parameter}
                      value={value}
                      onUpdate={onUpdate}
                    />
                  );
                }
                if (parameter.parameterType === "Option") {
                  if (parameter.dataType === "Enum") {
                    return (
                      <OptionEnumInput
                        key={parameter.key}
                        parameter={parameter}
                        value={value}
                        onUpdate={onUpdate}
                      />
                    );
                  }
                  if (parameter.dataType === "Boolean") {
                    return (
                      <OptionBooleanInput
                        key={parameter.key}
                        parameter={parameter}
                        value={value}
                        onUpdate={onUpdate}
                      />
                    );
                  }
                  return (
                    <OptionTextInput
                      key={parameter.key}
                      parameter={parameter}
                      value={value}
                      onUpdate={onUpdate}
                    />
                  );
                }
                return null;
              })
          ) : (
            <p className="text-sm text-muted-foreground">
              No parameters available for this command.
            </p>
          )}
        </div>
      )}
    </React.Fragment>
  );
}

import { z } from "zod/v4";

export const CommandSchema = z.object({
  key: z.string(),
  parentCommandKey: z.string().optional(),
  name: z.string(),
  description: z.string().optional(),
  isDefault: z.boolean().optional(),
  sortOrder: z.number().optional(),
});
export type Command = z.infer<typeof CommandSchema>;

export const ParameterEnumValueSchema = z.object({
  key: z.string(),
  parameterKey: z.string(),
  value: z.string(),
  displayName: z.string(),
  description: z.string().optional(),
  isDefault: z.boolean().optional(),
  sortOrder: z.number().optional(),
});
export type ParameterEnumValue = z.infer<typeof ParameterEnumValueSchema>;

export const ParameterValidationTypeSchema = z.enum([
  "min_length",
  "max_length",
  "min_value",
  "max_value",
  "regex",
]);
export type ParameterValidationType = z.infer<typeof ParameterValidationTypeSchema>;

export const ParameterValidationSchema = z.object({
  key: z.string(),
  parameterKey: z.string(),
  validationType: ParameterValidationTypeSchema,
  validationValue: z.string(),
  errorMessage: z.string(),
});
export type ParameterValidation = z.infer<typeof ParameterValidationSchema>;
export const ParameterDependencyTypeSchema = z.enum(["requires", "conflicts_with"]);
export type ParameterDependencyType = z.infer<typeof ParameterDependencyTypeSchema>;
export const ParameterDependencySchema = z.object({
  key: z.string(),
  parameterKey: z.string(),
  dependsOnParameterKey: z.string(),
  dependencyType: ParameterDependencyTypeSchema,
  conditionValue: z.string().optional(),
});

export type ParameterValue = string | number | boolean;

export type ParameterDependency = z.infer<typeof ParameterDependencySchema>;

export const ParameterMetadataSchema = z.object({
  tags: z.array(z.string()).optional(),
});
export type ParameterMetadata = z.infer<typeof ParameterMetadataSchema>;
export const ParameterTypeSchema = z.enum(["Flag", "Option", "Argument"]);
export type ParameterType = z.infer<typeof ParameterTypeSchema>;

export const ParameterDataTypeSchema = z.enum(["String", "Number", "Boolean", "Enum"]);
export type ParameterDataType = z.infer<typeof ParameterDataTypeSchema>;

export const ParameterSchema = z.object({
  key: z.string(),
  name: z.string(),
  commandKey: z.string().optional(),
  description: z.string().optional(),
  metadata: ParameterMetadataSchema.optional(),
  parameterType: ParameterTypeSchema,
  dataType: ParameterDataTypeSchema,
  isRequired: z.boolean(),
  isRepeatable: z.boolean(),
  isGlobal: z.boolean(),
  defaultValue: z.string().optional(),
  shortFlag: z.string().optional(),
  longFlag: z.string(),
  position: z.number().optional(),
  sortOrder: z.number().optional(),
  arraySeparator: z.string().optional(),
  keyValueSeparator: z.string().optional(),
  enumValues: z.array(ParameterEnumValueSchema).optional(),
  validations: z.array(ParameterValidationSchema).optional(),
  dependencies: z.array(ParameterDependencySchema).optional(),
});
export type Parameter = z.infer<typeof ParameterSchema>;

export const ExclusionTypeSchema = z.enum(["mutual_exclusive", "required_one_of"]);
export type ExclusionType = z.infer<typeof ExclusionTypeSchema>;

export const ExclusionGroupSchema = z.object({
  key: z.string().optional(),
  commandKey: z.string().optional(),
  name: z.string(),
  exclusionType: ExclusionTypeSchema,
  parameterKeys: z.array(z.string()),
});
export type ExclusionGroup = z.infer<typeof ExclusionGroupSchema>;

export const SavedCommandSchema = z.object({
  key: z.string(),
  command: z.string(),
});
export type SavedCommand = z.infer<typeof SavedCommandSchema>;

export const ToolMetadataSchema = z.record(z.string(), z.any());
export type ToolMetadata = z.infer<typeof ToolMetadataSchema>;

export const ToolSchema = z.object({
  name: z.string(),
  displayName: z.string(),
  description: z.string().optional(),
  version: z.string().optional(),
  category: z.string().optional(),
  tags: z.array(z.string()).optional(),
  url: z.url().optional(),
  commands: z.array(CommandSchema),
  parameters: z.array(ParameterSchema),
  exclusionGroups: z.array(ExclusionGroupSchema).optional(),
  metadata: ToolMetadataSchema.optional(),
});
export type Tool = z.infer<typeof ToolSchema>;

export const AIParseRequestSchema = z.object({
  helpText: z.string(),
  toolName: z.string().optional(),
});
export type AIParseRequest = z.infer<typeof AIParseRequestSchema>;

export const AIParseResponseSchema = z.object({
  success: z.boolean(),
  data: ToolSchema.optional(),
  error: z.string().optional(),
});
export type AIParseResponse = z.infer<typeof AIParseResponseSchema>;

export const newToolSchema = z.object({
  displayName: z.string(),
  name: z.string(),
  version: z.string().optional(),
  description: z.string().optional(),
  url: z.url().optional(),
});
export type ManualNewTool = z.infer<typeof newToolSchema>;

import {
  ExclusionTypeSchema,
  ParameterDataTypeSchema,
  ParameterDependencyTypeSchema,
  ParameterEnumValueSchema,
  ParameterMetadataSchema,
  ParameterTypeSchema,
  ParameterValidationSchema,
} from "./commandly";
import { z } from "zod/v4";

export const NestedParameterEnumValueSchema = ParameterEnumValueSchema.omit({
  key: true,
  parameterKey: true,
});
export type NestedParameterEnumValue = z.infer<typeof NestedParameterEnumValueSchema>;

export const NestedParameterValidationSchema = ParameterValidationSchema.omit({
  key: true,
  parameterKey: true,
});
export type NestedParameterValidation = z.infer<typeof NestedParameterValidationSchema>;

export const NestedParameterDependencySchema = z.object({
  dependsOnParameter: z.string(),
  dependencyType: ParameterDependencyTypeSchema,
  conditionValue: z.string().optional(),
});
export type NestedParameterDependency = z.infer<typeof NestedParameterDependencySchema>;

export const NestedParameterSchema: z.ZodType<object> = z.lazy(() =>
  z.object({
    name: z.string(),
    description: z.string(),
    parameterType: ParameterTypeSchema,
    dataType: ParameterDataTypeSchema,
    metadata: ParameterMetadataSchema.optional(),
    isRequired: z.boolean(),
    isRepeatable: z.boolean(),
    isGlobal: z.boolean(),
    defaultValue: z.string().optional(),
    shortFlag: z.string().optional(),
    longFlag: z.string(),
    position: z.number().optional(),
    sortOrder: z.number().optional(),
    arraySeparator: z.string().optional(),
    keyValueSeparator: z.string().optional(),
    enumValues: z.array(NestedParameterEnumValueSchema).optional(),
    validations: z.array(NestedParameterValidationSchema).optional(),
    dependencies: z.array(NestedParameterDependencySchema).optional(),
  }),
);
export type NestedParameter = z.infer<typeof NestedParameterSchema>;

export const NestedCommandSchema: z.ZodType<object> = z.lazy(() =>
  z.object({
    name: z.string(),
    description: z.string(),
    isDefault: z.boolean(),
    sortOrder: z.number(),
    parameters: z.array(NestedParameterSchema),
    subcommands: z.array(NestedCommandSchema),
  }),
);
export type NestedCommand = z.infer<typeof NestedCommandSchema>;

export const NestedExclusionGroupSchema = z.object({
  name: z.string(),
  exclusionType: ExclusionTypeSchema,
  parameters: z.array(z.string()),
});
export type NestedExclusionGroup = z.infer<typeof NestedExclusionGroupSchema>;

export const NestedToolMetadataSchema = z.record(z.string(), z.any());
export type NestedToolMetadata = z.infer<typeof NestedToolMetadataSchema>;

export const NestedToolSchema = z.object({
  name: z.string(),
  displayName: z.string(),
  description: z.string().optional(),
  version: z.string().optional(),
  url: z.url().optional(),
  globalParameters: z.array(NestedParameterSchema),
  commands: z.array(NestedCommandSchema),
  exclusionGroups: z.array(NestedExclusionGroupSchema).optional().nullable(),
  metadata: NestedToolMetadataSchema.optional(),
});
export type NestedTool = z.infer<typeof NestedToolSchema>;

import type {
  Command,
  ExclusionGroup,
  Parameter,
  SavedCommand,
  Tool,
} from "@/registry/commandly/lib/types/commandly";

export const buildCommandHierarchy = (commands: Command[]): Command[] => {
  return commands.sort(
    (a, b) => (a.sortOrder ?? commands.indexOf(a)) - (b.sortOrder ?? commands.indexOf(b)),
  );
};

export const slugify = (text: string): string => {
  return text
    .toString()
    .toLowerCase()
    .trim()
    .replace(/\s+/g, "-") // Replace spaces with -
    .replace(/[^\w-]+/g, "") // Remove all non-word chars
    .replace(/--+/g, "-") // Replace multiple - with single -
    .replace(/^-+/, "") // Trim - from start of text
    .replace(/-+$/, ""); // Trim - from end of text
};

export const getCommandPath = (command: Command, tool: Tool): string => {
  const findCommandPath = (
    targetKey: string,
    commands: Command[],
    path: string[] = [],
  ): string[] | null => {
    for (const cmd of commands) {
      if (cmd.name === targetKey) {
        return [...path, cmd.name];
      }

      const childCommands = commands.filter((c) => c.parentCommandKey === cmd.key);
      if (childCommands.length > 0) {
        const subPath = findCommandPath(targetKey, childCommands, [...path, cmd.name]);
        if (subPath) {
          return subPath;
        }
      }
    }
    return null;
  };

  const rootCommands = tool.commands.filter((c) => !c.parentCommandKey);
  const path = findCommandPath(command.name, rootCommands);

  if (!path) return command.name;

  if (command.name === tool.name && command.isDefault) {
    return tool.name;
  }

  const rootCommand = tool.commands.find((c) => c.name === tool.name);
  if (rootCommand?.isDefault && path[0] === tool.name) {
    path[0] = tool.name;
  }

  return path.join(" ");
};

export const getAllSubcommands = (commandKey: string, commands: Command[]): Command[] => {
  const result: Command[] = [];

  const findSubcommands = (parentKey: string) => {
    commands.forEach((cmd) => {
      if (cmd.parentCommandKey === parentKey) {
        result.push(cmd);
        findSubcommands(cmd.key);
      }
    });
  };

  findSubcommands(commandKey);
  return result;
};

export const exportToStructuredJSON = (tool: Tool) => {
  const flattenCommand = (cmd: Command) => {
    return { ...cmd };
  };

  return {
    name: tool.name,
    displayName: tool.displayName,
    description: tool.description,
    version: tool.version,
    commands: tool.commands.map(flattenCommand),
    parameters: tool.parameters,
    exclusionGroups: tool.exclusionGroups,
    metadata: tool.metadata,
  };
};

export const flattenImportedData = (importedData: Record<string, unknown>): Tool => {
  const {
    name,
    displayName,
    commands = [],
    exclusionGroups = [],
    metadata = {
      supportedInput: [],
      supportedOutput: [],
    },
  } = importedData as {
    name: string;
    displayName?: string;
    parameters?: Parameter[];
    commands?: Record<string, unknown>[];
    exclusionGroups?: ExclusionGroup[];
    metadata?: Tool["metadata"];
  };

  const allParameters: Parameter[] = [];

  const flattenCommandParameters = (
    command: Record<string, unknown>,
    parentKey?: string,
  ): Command[] => {
    const {
      parameters = [],
      subcommands = [],
      ...commandData
    } = command as {
      parameters?: Parameter[];
      subcommands?: Record<string, unknown>[];
      [key: string]: unknown;
    };

    (parameters as Parameter[]).forEach((param: Parameter) => {
      allParameters.push({
        ...param,
        commandKey: command.key as string,
        isGlobal: !command.name,
      });
    });

    const flatCommand: Command = {
      ...commandData,
      parentCommandKey: parentKey,
    } as Command;

    const flatCommands = [flatCommand];

    (subcommands as Record<string, unknown>[]).forEach((subcmd) => {
      flatCommands.push(...flattenCommandParameters(subcmd, command.key as string));
    });

    return flatCommands;
  };

  const flatCommands: Command[] = [];
  (commands as Record<string, unknown>[]).forEach((cmd) => {
    flatCommands.push(...flattenCommandParameters(cmd));
  });

  return {
    name: name,
    displayName: displayName || name,
    commands: flatCommands,
    parameters: allParameters,
    exclusionGroups,
    metadata,
  };
};

