export const validateDefaultValue = (
  parameter: Parameter,
): { isValid: boolean; error?: string } => {
  const { defaultValue, validations, dataType } = parameter;

  if (!defaultValue || !validations) return { isValid: true };

  switch (dataType) {
    case "Number":
      if (!/^-?\d+$/.test(defaultValue)) {
        return { isValid: false, error: "Default value must be an integer" };
      }
      break;
    case "Boolean":
      if (!["true", "false", "1", "0"].includes(defaultValue.toLowerCase())) {
        return {
          isValid: false,
          error: "Default value must be true/false or 1/0",
        };
      }
      break;
  }

  for (const validation of validations) {
    const value = dataType === "Number" ? Number(defaultValue) : defaultValue;

    switch (validation.validationType) {
      case "min_length":
        if (typeof value === "string" && value.length < Number(validation.validationValue)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value too short",
          };
        }
        break;
      case "max_length":
        if (typeof value === "string" && value.length > Number(validation.validationValue)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value too long",
          };
        }
        break;
      case "min_value":
        if (typeof value === "number" && value < Number(validation.validationValue)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value too small",
          };
        }
        break;
      case "max_value":
        if (typeof value === "number" && value > Number(validation.validationValue)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value too large",
          };
        }
        break;
      case "regex":
        if (typeof value === "string" && !new RegExp(validation.validationValue).test(value)) {
          return {
            isValid: false,
            error: validation.errorMessage || "Value doesn't match pattern",
          };
        }
        break;
    }
  }

  return { isValid: true };
};

export const createNewCommand = (parentKey?: string): Command => {
  const name = randomCommandName();
  return {
    key: slugify(name),
    parentCommandKey: parentKey,
    name,
    isDefault: false,
    sortOrder: 1,
  };
};

export const createNewParameter = (isGlobal: boolean, commandKey?: string): Parameter => {
  return {
    key: "",
    name: "",
    commandKey: isGlobal ? undefined : commandKey,
    parameterType: "Option",
    dataType: "String",
    isRequired: false,
    isRepeatable: false,
    isGlobal,
    longFlag: "",
  };
};

export const getSavedCommandsFromStorage = (toolId: string): SavedCommand[] => {
  try {
    const saved = localStorage.getItem(`saved-${toolId}`);
    return saved ? JSON.parse(saved) : [];
  } catch {
    return [];
  }
};

export const saveSavedCommandsToStorage = (toolId: string, commands: SavedCommand[]): void => {
  try {
    localStorage.setItem(toolId, JSON.stringify(commands));
  } catch (error) {
    console.error("Failed to save commands to localStorage:", error);
  }
};

export const addSavedCommandToStorage = (toolId: string, command: SavedCommand): void => {
  const existingCommands = getSavedCommandsFromStorage(toolId);
  const updatedCommands = [...existingCommands, command];
  saveSavedCommandsToStorage(toolId, updatedCommands);
};

export const removeSavedCommandFromStorage = (toolId: string, commandKey: string): void => {
  const existingCommands = getSavedCommandsFromStorage(toolId);
  const updatedCommands = existingCommands.filter((cmd) => cmd.key !== commandKey);
  saveSavedCommandsToStorage(toolId, updatedCommands);
};

export const clearSavedCommandsFromStorage = (toolId: string): void => {
  localStorage.removeItem(toolId);
};

export const randomCommandName = () => {
  const characters = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";
  let result = "";
  const charactersLength = characters.length;
  for (let i = 0; i < 7; i++) {
    result += characters.charAt(Math.floor(Math.random() * charactersLength));
  }
  return result;
};

export function generateHashCode(s: string): string {
  let h = 0;
  for (let i = 0; i < s.length; i++) h = (Math.imul(31, h) + s.charCodeAt(i)) | 0;

  return h.toString();
}

import {
  NestedCommand,
  NestedExclusionGroup,
  NestedParameter,
  NestedTool,
} from "../types/commandly-nested";
import type { Tool, Command, Parameter } from "@/registry/commandly/lib/types/commandly";

export const convertToNestedStructure = (tool: Tool): NestedTool => {
  const globalParameters = tool.parameters.filter((p) => p.isGlobal);

  const convertParameter = (param: Parameter): NestedParameter => {
    const { ...rest } = param;
    return {
      ...rest,
      validations: param.validations?.map((v) => {
        return {
          validationType: v.validationType,
          validationValue: v.validationValue,
          errorMessage: v.errorMessage,
        };
      }),
      metadata: param.metadata,
      dataType: param.dataType,
      dependencies: param.dependencies?.map((dep) => {
        const dependsOnParam = tool.parameters.find((p) => p.key === dep.dependsOnParameterKey);
        return {
          dependsOnParameter: dependsOnParam?.longFlag || "",
          dependencyType: dep.dependencyType,
          conditionValue: dep.conditionValue,
        };
      }),
    };
  };

  const buildNestedCommands = (commands: Command[], parentKey?: string): NestedCommand[] => {
    return commands
      .filter((cmd) => cmd.parentCommandKey === parentKey)
      .map((cmd) => {
        const commandParameters = tool.parameters.filter(
          (p) => p.commandKey === cmd.key && !p.isGlobal,
        );
        return {
          name: cmd.name,
          description: cmd.description,
          isDefault: cmd.isDefault,
          sortOrder: cmd.sortOrder,
          parameters: commandParameters.map(convertParameter),
          subcommands: buildNestedCommands(commands, cmd.key),
        };
      });
  };

  const nestedExclusionGroups: NestedExclusionGroup[] | undefined = tool.exclusionGroups?.map(
    (group) => {
      return {
        name: group.name,
        exclusionType: group.exclusionType,
        parameters: group.parameterKeys.map((pk) => {
          const param = tool.parameters.find((p) => p.key === pk);
          return param?.longFlag || "";
        }),
      };
    },
  );

  return {
    name: tool.name,
    url: tool.url,
    displayName: tool.displayName,
    description: tool.description,
    version: tool.version,
    metadata: tool.metadata,
    globalParameters: globalParameters.map(convertParameter),
    commands: buildNestedCommands(tool.commands),
    exclusionGroups: nestedExclusionGroups,
  };
};
